{
  "query": "query { usage { usage { features { feature used limit remaining resetAt } } } } }",
  "variables": {}
}

{
  "query": "query GetUsage($feature: String) { usage { usage(feature: $feature) { features { feature used limit remaining resetAt } } } } }",
  "variables": { "feature": "{{featureName}}" }
}

{
  "query": "query FeatureOverview($feature: String!) { featureOverview { featureOverview(feature: $feature) { feature usage { feature used limit remaining resetAt } activities { id serviceType actionType status resultCount createdAt } jobs { id jobId jobType status createdAt } } } } }",
  "variables": { "feature": "{{featureName}}" }
}

{
  "query": "mutation TrackUsage($input: TrackUsageInput!) { usage { trackUsage(input: $input) { feature used limit success } } } }",
  "variables": { "input": { "feature": "{{featureName}}", "amount": 1 } }
}

{
  "query": "mutation ResetUsage($input: ResetUsageInput!) { usage { resetUsage(input: $input) { feature used limit success } } } }",
  "variables": { "input": { "feature": "{{featureName}}" } }
}
